mapper.select:
SELECT id, user_id, merchant_id, dish_id, dish_name, dish_image, base_price, unit_price, qty, options_text, options_snapshot, create_time, update_time FROM cart WHERE user_id = #{userId} AND merchant_id = #{merchantId} AND dish_id = #{dishId}
AND options_snapshot = #{optionsSnapshot} AND options_snapshot IS NULL
LIMIT 1
